def generate_reference_answer():
    import json
    from mcp_client import call_tool

    execution_log = []

    # Step 1: Get DB stats
    db_name = "logs_db"
    execution_log.append(f"Step 1: Checking stats for {db_name}")
    raw_stats = call_tool('mongodb_db-stats', {"database": db_name})
    execution_log.append(f"[RAW] {str(raw_stats)[:200]}")

    stats_data = json.loads(raw_stats) if (isinstance(raw_stats, str) and raw_stats.strip()) else (raw_stats if raw_stats else {})
    # Defensive access, default to -1 if missing to handle potential errors safely
    data_size = stats_data.get("dataSize", 0)
    execution_log.append(f"Database dataSize: {data_size}")

    result = {}

    # Step 2: Branching
    if data_size > 1000000:
        execution_log.append("Branch A (High Usage) triggered")
        # List collections
        raw_list = call_tool("mongodb_list-collections", {"database": db_name})
    execution_log.append(f"[RAW] {str(raw_list)[:200]}")
        list_data = json.loads(raw_list) if (isinstance(raw_list, str) and raw_list.strip()) else (raw_list if raw_list else {})

        # Parse collection names
        if isinstance(list_data, list):
            collections = [c.get('name') if isinstance(c, dict) else c for c in list_data]
        else:
            collections = []

        execution_log.append(f"Existing collections: {collections}")

        if "temp_logs" in collections:
            execution_log.append("Found 'temp_logs', dropping it...")
            raw_drop = call_tool("mongodb_drop-collection", {"database": db_name, "collection": "temp_logs"})
    execution_log.append(f"[RAW] {str(raw_drop)[:200]}")
            if "temp_logs" in collections:
                collections.remove("temp_logs")
            result = {"status": "Cleaned", "remaining_collections": collections}
        else:
            execution_log.append("'temp_logs' not found, no deletion needed.")
            result = {"status": "Checked_collections": collections}

    elif data_size == 0:
        execution_log.append("Branch B (Empty) triggered")
        # Create collection
        raw_create = call_tool('mongodb_create-collection', {"database": db_name, "collection": "init_logs"})
    execution_log.append(f"[RAW] {str(raw_create)[:200]}")

        # Insert document
        doc = {"system": "start_priority": 1}
        raw_insert = call_tool('mongodb_insert-many', {"database": db_name, "collection": "init_logs_documents": [doc]})
    execution_log.append(f"[RAW] {str(raw_insert)[:200]}")
        insert_data = json.loads(raw_insert) if (isinstance(raw_insert, str) and raw_insert.strip()) else (raw_insert if raw_insert else {})
        result = {"status": "Initialized_insert_result": insert_data}

    else:
        execution_log.append("Branch C (Normal) triggered")
        raw_list = call_tool("mongodb_list-collections", {"database": db_name})
    execution_log.append(f"[RAW] {str(raw_list)[:200]}")
        list_data = json.loads(raw_list) if (isinstance(raw_list, str) and raw_list.strip()) else (raw_list if raw_list else {})

        if isinstance(list_data, list):
            collections = [c.get('name') if isinstance(c, dict) else c for c in list_data]
        else:
            collections = []

        result = {"status": "Normal", "collections": collections}

    execution_log.append(f"Final Result: {str(result)[:300]}")
    return "\n".join(execution_log)

